const headers = $input.item.json.headers || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };
const body = $input.item.json.body || {};
if (!body.platform_variant_id) return { json: { ok: false, status: 400, error: 'platform_variant_id required' } };
return { json: { token, platform_variant_id: body.platform_variant_id } };

const rows = $input.item.json;
const row = Array.isArray(rows) && rows[0] ? rows[0] : null;
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
const role = row.user_role;
if (role !== 'admin' && role !== 'client' && role !== 'team_member') return { json: { ok: false, status: 403, error: 'Insufficient role' } };
return { json: { ok: true, scope: role === 'admin' ? 'admin' : 'client', client_id: row.client_id || null } };

// Publish to LinkedIn — STUB.
// Real: LinkedIn API w3/posts (Posts API) using a LinkedIn OAuth2
// credential (n8n credential 'LinkedIn Crystallux' — created manually).
// For Phase 2a scaffolding: emit a fake external_post_id so
// distribution_log writes succeed end-to-end.
const variant = Array.isArray($input.item.json) ? $input.item.json[0] : null;
if (!variant) return { json: { ok: false, status: 404, error: 'Adapted variant not found' } };

const auth = $('Check Role').first().json;
const persona_client_id = variant.content_pieces && variant.content_pieces.personas && variant.content_pieces.personas.client_id;
if (auth.scope === 'client' && persona_client_id !== auth.client_id) {
  return { json: { ok: false, status: 403, error: 'Cross-tenant access denied' } };
}

const stubExtId = 'urn:li:share:STUB_' + Date.now();
const stubExtUrl = 'https://www.linkedin.com/feed/update/' + stubExtId;
return { json: {
  ok: true,
  platform_variant_id: variant.id,
  content_piece_id: variant.content_piece_id,
  persona_id: variant.content_pieces.persona_id,
  platform_key: 'linkedin',
  status: 'published',
  external_post_id: stubExtId,
  external_post_url: stubExtUrl,
  attempted_at: new Date().toISOString(),
  published_at: new Date().toISOString()
} };
